content.text:
Promise aşağıdakı şəkildə yaradılır:
```javascript
const promise = new Promise((resolve, reject) => {
  // Asinxron əməliyyat
  if (/* uğurlu nəticə */) {
    resolve(deyer);
  } else {
    reject(xeta);
  }
});
```
- `resolve`: Əməliyyat uğurlu olduqda çağırılır və dəyəri qaytarır.
- `reject`: Əməliyyat uğursuz olduqda çağırılır və xəta qaytarır.
Promise-dən istifadə üçün `.then()` və `.catch()` metodları istifadə olunur.

content.code:
// Sadə Promise nümunəsi
const myPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const data = { id: 1, name: 'Ali' };
    resolve(data);
  }, 1000);
});

myPromise
  .then(data => console.log('Məlumat alındı: ', data.name))
  .catch(error => console.log('Xəta: ', error)); // 1 saniyə sonra: Məlumat alındı: Ali

// Xəta ilə Promise nümunəsi
const errorPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    reject('Məlumat alınmadı');
  }, 1000);
});

errorPromise
  .then(data => console.log(data))
  .catch(error => console.log('Xəta: ', error)); // 1 saniyə sonra: Xəta: Məlumat alınmadı

// Promise zəncirləmə nümunəsi
const fetchData = new Promise((resolve) => {
  setTimeout(() => {
    resolve({ id: 2, name: 'Veli' });
  }, 1000);
});

fetchData
  .then(data => {
    console.log('İlk məlumat: ', data.name);
    return data.name.toUpperCase();
  })
  .then(upperName => console.log('Böyük hərflərlə: ', upperName))
  .catch(error => console.log('Xəta: ', error)); // 1 saniyə sonra: İlk məlumat: Veli, Böyük hərflərlə: VELI

// Səhvə yol açan nümunə
const badPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const data = null;
    resolve(data);
  }, 1000);
});

badPromise.then(data => console.log(data.name)); // TypeError: Cannot read property 'name' of null

// Düzgün yol
const safePromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const data = null;
    if (data) {
      resolve(data);
    } else {
      reject('Məlumat yoxdur');
    }
  }, 1000);
});

safePromise
  .then(data => console.log('Məlumat: ', data.name))
  .catch(error => console.log('Xəta: ', error)); // Xəta: Məlumat yoxdur

// Promise.all nümunəsi
const promise1 = new Promise((resolve) => {
  setTimeout(() => resolve('Birinci nəticə'), 1000);
});

const promise2 = new Promise((resolve) => {
  setTimeout(() => resolve('İkinci nəticə'), 2000);
});

Promise.all([promise1, promise2])
  .then(results => console.log('Bütün nəticələr: ', results))
  .catch(error => console.log('Xəta: ', error)); // 2 saniyə sonra: Bütün nəticələr: ['Birinci nəticə', 'İkinci nəticə']

