content.text:
A Promise is created as follows:
```javascript
const promise = new Promise((resolve, reject) => {
  // Asynchronous operation
  if (/* successful result */) {
    resolve(value);
  } else {
    reject(error);
  }
});
```
- `resolve`: Called when the operation succeeds, returning a value.
- `reject`: Called when the operation fails, returning an error.
Promises are handled using `.then()` and `.catch()` methods.

content.code:
// Simple Promise example
const myPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const data = { id: 1, name: 'Ali' };
    resolve(data);
  }, 1000);
});

myPromise
  .then(data => console.log('Data received: ', data.name))
  .catch(error => console.log('Error: ', error)); // After 1 second: Data received: Ali

// Promise with error example
const errorPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    reject('Data fetch failed');
  }, 1000);
});

errorPromise
  .then(data => console.log(data))
  .catch(error => console.log('Error: ', error)); // After 1 second: Error: Data fetch failed

// Promise chaining example
const fetchData = new Promise((resolve) => {
  setTimeout(() => {
    resolve({ id: 2, name: 'Veli' });
  }, 1000);
});

fetchData
  .then(data => {
    console.log('Initial data: ', data.name);
    return data.name.toUpperCase();
  })
  .then(upperName => console.log('Uppercase: ', upperName))
  .catch(error => console.log('Error: ', error)); // After 1 second: Initial data: Veli, Uppercase: VELI

// Error-prone example
const badPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const data = null;
    resolve(data);
  }, 1000);
});

badPromise.then(data => console.log(data.name)); // TypeError: Cannot read property 'name' of null

// Correct approach
const safePromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const data = null;
    if (data) {
      resolve(data);
    } else {
      reject('No data available');
    }
  }, 1000);
});

safePromise
  .then(data => console.log('Data: ', data.name))
  .catch(error => console.log('Error: ', error)); // Error: No data available

// Promise.all example
const promise1 = new Promise((resolve) => {
  setTimeout(() => resolve('First result'), 1000);
});

const promise2 = new Promise((resolve) => {
  setTimeout(() => resolve('Second result'), 2000);
});

Promise.all([promise1, promise2])
  .then(results => console.log('All results: ', results))
  .catch(error => console.log('Error: ', error)); // After 2 seconds: All results: ['First result', 'Second result']

