Promise создается следующим образом:
```javascript
const promise = new Promise((resolve, reject) => {
  // Асинхронная операция
  if (/* успешный результат */) {
    resolve(значение);
  } else {
    reject(ошибка);
  }
});
```
- `resolve`: Вызывается при успешном завершении операции, возвращает значение.
- `reject`: Вызывается при неудаче, возвращает ошибку.
Promise управляются с помощью методов `.then()` и `.catch()`.

content.code:
// Простой пример Promise
const myPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const data = { id: 1, name: 'Али' };
    resolve(data);
  }, 1000);
});

myPromise
  .then(data => console.log('Данные получены: ', data.name))
  .catch(error => console.log('Ошибка: ', error)); // Через 1 секунду: Данные получены: Али

// Пример Promise с ошибкой
const errorPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    reject('Не удалось получить данные');
  }, 1000);
});

errorPromise
  .then(data => console.log(data))
  .catch(error => console.log('Ошибка: ', error)); // Через 1 секунду: Ошибка: Не удалось получить данные

// Пример цепочки Promise
const fetchData = new Promise((resolve) => {
  setTimeout(() => {
    resolve({ id: 2, name: 'Вали' });
  }, 1000);
});

fetchData
  .then(data => {
    console.log('Исходные данные: ', data.name);
    return data.name.toUpperCase();
  })
  .then(upperName => console.log('В верхнем регистре: ', upperName))
  .catch(error => console.log('Ошибка: ', error)); // Через 1 секунду: Исходные данные: Вали, В верхнем регистре: ВАЛИ

// Пример с ошибкой
const badPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const data = null;
    resolve(data);
  }, 1000);
});

badPromise.then(data => console.log(data.name)); // TypeError: Cannot read property 'name' of null

// Правильный подход
const safePromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const data = null;
    if (data) {
      resolve(data);
    } else {
      reject('Данные отсутствуют');
    }
  }, 1000);
});

safePromise
  .then(data => console.log('Данные: ', data.name))
  .catch(error => console.log('Ошибка: ', error)); // Ошибка: Данные отсутствуют

// Пример Promise.all
const promise1 = new Promise((resolve) => {
  setTimeout(() => resolve('Первый результат'), 1000);
});

const promise2 = new Promise((resolve) => {
  setTimeout(() => resolve('Второй результат'), 2000);
});

Promise.all([promise1, promise2])
  .then(results => console.log('Все результаты: ', results))
  .catch(error => console.log('Ошибка: ', error)); // Через 2 секунды: Все результаты: ['Первый результат', 'Второй результат']

